1	export type Item = {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	};
7	
8	export type QuoteStep = { op: "quote"; items: Item[] };
9	export type Step = QuoteStep;
10	
11	export type Scenario = {
12	  customer: { yearsWithMHPCO: number };
13	  steps: Step[];
14	};
15	
16	export type QuoteResult = { premium: number };
17	export type StepResult = QuoteResult;
18	export type ScenarioResult = { results: StepResult[] };
19	
20	const PROCESSING_FEE = 5;
21	// Premiums are accumulated in hundredths of a gold piece so we can apply
22	// percentage surcharges/discounts (10%, 15%, 20%, 30%, 50%) with integer math
23	// and round once at the end (avoids floating-point artifacts).
24	const HUNDREDTHS_PER_UNIT = 100;
25	
26	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
27	  sword: 100,
28	  amulet: 60,
29	  staff: 80,
30	  potion: 40,
31	  rune: 25,
32	  moonstone: 25,
33	};
34	
35	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
36	const BLOCK_SIZE = 3;
37	const BLOCK_BASE_PREMIUM = 60;
38	
39	const basePremium = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
40	
41	const sumBasePremiums = (items: Item[]): number =>
42	  items.reduce((sum, item) => sum + basePremium(item), 0);
43	
44	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
45	
46	const groupByType = (items: Item[]): Item[][] => {
47	  const groups: Record<string, Item[]> = {};
48	  for (const item of items) {
49	    (groups[item.type] ??= []).push(item);
50	  }
51	  return Object.values(groups);
52	};
53	
54	const componentGroupBasePremium = (group: Item[]): number =>
55	  group.length === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : sumBasePremiums(group);
56	
57	const itemsBasePremium = (items: Item[]): number => {
58	  const components = items.filter(isComponent);
59	  const mains = items.filter((item) => !isComponent(item));
60	  const componentTotal = groupByType(components)
61	    .map(componentGroupBasePremium)
62	    .reduce((sum, premium) => sum + premium, 0);
63	  return sumBasePremiums(mains) + componentTotal;
64	};
65	
66	const roundUpHundredthsToUnits = (h: number): number => Math.ceil(h / HUNDREDTHS_PER_UNIT);
67	
68	// Modifier rates are expressed in hundredths-per-gold of base premium (i.e. percentage points).
69	// Item-specific modifiers attach to a single item's base premium.
70	// Policy-wide modifiers attach to the total base premium of the policy.
71	const CURSE_SURCHARGE = 50;
72	const HIGH_ENCHANTMENT_SURCHARGE = 30;
73	const HIGH_ENCHANTMENT_THRESHOLD = 5;
74	const FIRST_QUOTE_SURCHARGE = 10;
75	const LOYALTY_DISCOUNT = 20;
76	const LOYALTY_THRESHOLD_YEARS = 2;
77	const FOLLOWUP_DISCOUNT = 15;
78	
79	const itemModifierRate = (item: Item): number => {
80	  let rate = 0;
81	  if (item.cursed) rate += CURSE_SURCHARGE;
82	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) rate += HIGH_ENCHANTMENT_SURCHARGE;
83	  return rate;
84	};
85	
86	const itemSurchargeHundredths = (item: Item): number => basePremium(item) * itemModifierRate(item);
87	
88	const sumItemSurchargesHundredths = (items: Item[]): number =>
89	  items.reduce((sum, item) => sum + itemSurchargeHundredths(item), 0);
90	
91	type Customer = { yearsWithMHPCO: number };
92	
93	const policyModifierRate = (customer: Customer, quoteIndex: number): number => {
94	  let rate = FIRST_QUOTE_SURCHARGE;
95	  if (customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) rate -= LOYALTY_DISCOUNT;
96	  if (quoteIndex > 0) rate -= FOLLOWUP_DISCOUNT;
97	  return rate;
98	};
99	
100	const quote = (step: QuoteStep, customer: Customer, quoteIndex: number): QuoteResult => {
101	  const baseGold = itemsBasePremium(step.items);
102	  const baseHundredths = baseGold * HUNDREDTHS_PER_UNIT;
103	  const itemSurcharges = sumItemSurchargesHundredths(step.items);
104	  const policyAdj = baseGold * policyModifierRate(customer, quoteIndex);
105	  const totalHundredths = baseHundredths + itemSurcharges + policyAdj;
106	  return { premium: roundUpHundredthsToUnits(totalHundredths) + PROCESSING_FEE };
107	};
108	
109	export const runScenario = (scenario: Scenario): ScenarioResult => {
110	  let quoteIndex = 0;
111	  const results: StepResult[] = [];
112	  for (const step of scenario.steps) {
113	    if (step.op === "quote") {
114	      results.push(quote(step, scenario.customer, quoteIndex));
115	      quoteIndex += 1;
116	    }
117	  }
118	  return { results };
119	};
